PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?duration WHERE {
  ?game wdt:P1343 wd:Q31707433.
  {
    ?game wdt:P5003 wd:Q434705.
    ?game wdt:P2346 wd:Q32184.
  } UNION {
    ?game wdt:P5003 wd:Q32184.
    ?game wdt:P2346 wd:Q434705.
  }
  ?game wdt:P2016 ?duration.
}
ORDER BY ASC(?duration)
LIMIT 1

